// node-condition build: top-level await -> esbuild cannot emit --format=cjs (like lexical's
// Lexical.node.mjs). Currently turbo-test picks THIS, fails the CJS compile, falls back to raw
// .mjs -> V8 "Unexpected token 'export'".
const mod = await Promise.resolve({ tag: 'node-tla' });
export const marker = 'from-esm-node-mjs:' + mod.tag;
export function greet() { return 'hi-' + marker; }
